&lt;p&gt;Dans le code suivant, quelle valeur &lt;code&gt;couleur&lt;/code&gt; recevra le composant &lt;code&gt;MonTexte&lt;/code&gt; ?&lt;/p&gt;&lt;pre&gt;&lt;code&gt;const ThemeContext = createContext('rouge');

function App() {
  return (
    &lt;ThemeContext.Provider value="bleu"&gt;
      &lt;ThemeContext.Provider value="vert"&gt;
        &lt;MonTexte /&gt;
      &lt;/ThemeContext.Provider&gt;
    &lt;/ThemeContext.Provider&gt;
  );
}

function MonTexte() {
  const couleur = useContext(ThemeContext);
  return &lt;Text style={{ color: couleur }}&gt;Texte&lt;/Text&gt;;
}&lt;/code&gt;&lt;/pre&gt;

