&lt;p&gt;Voici un code qui utilise le Context API pour un thème :&lt;/p&gt;&lt;pre&gt;&lt;code&gt;const ThemeContext = createContext('clair');

function App() {
  const [theme, setTheme] = useState('clair');
  return (
    &lt;ThemeContext.Provider value={{ theme, setTheme }}&gt;
      &lt;EcranPrincipal /&gt;
    &lt;/ThemeContext.Provider&gt;
  );
}

function BoutonTheme() {
  const { setTheme } = useContext(ThemeContext);
  return &lt;Button onPress={() =&gt; setTheme('sombre')} /&gt;;
}&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;Que se passe-t-il lorsqu'on clique sur le bouton ?&lt;/p&gt;
